EXTRA_STRINGS = {
    "browser_pending_compress_zip_desc": ("将待处理列表中 %1$d 项压缩为一个 ZIP 文件，保存到当前目录。", "Compress %1$d pending items into one ZIP file in the current directory."),
    "browser_pending_compress_7z_desc": ("将待处理列表中 %1$d 项压缩为一个 7Z 文件，保存到当前目录。", "Compress %1$d pending items into one 7Z file in the current directory."),
    "browser_add_all_to_pending": ("全部加入待处理", "Add all to pending"),
    "browser_sort_desc": ("排序", "Sort"),
}

from pathlib import Path
for path in [Path(__file__).resolve().parents[1] / "app/src/main/res/values/strings.xml",
             Path(__file__).resolve().parents[1] / "app/src/main/res/values-en/strings.xml"]:
    content = path.read_text(encoding='utf-8')
    lang = 0 if 'values-en' not in str(path) else 1
    adds = []
    for k, (zh, en) in EXTRA_STRINGS.items():
        if f'name="{k}"' not in content:
            val = (zh if lang == 0 else en).replace('&', '&amp;').replace('<', '&lt;')
            adds.append(f'    <string name="{k}">{val}</string>')
    if adds:
        content = content.replace('</resources>', '\n'.join(adds) + '\n</resources>')
        path.write_text(content, encoding='utf-8')

count = 0
for old, new in REPLACEMENTS:
    if old in text:
        text = text.replace(old, new)
        count += 1
    else:
        print(f"MISSING: {old[:70]}...")

KT.write_text(text, encoding="utf-8")
print(f"Applied {count}/{len(REPLACEMENTS)} replacements")
